export function unescapeValue(rawValue, lineNo) {
  if (rawValue.startsWith('"')) {
    if (!rawValue.endsWith('"') || rawValue.length < 2) {
      throw new Error(`line ${lineNo}: unterminated quoted value`)
    }
    const inner = rawValue.slice(1, -1)
    let out = ''
    for (let j = 0; j < inner.length; j++) {
      const ch = inner[j]
      if (ch === '\\') {
        const next = inner[j + 1]
        if (next === 'n') out += '\n'
        else if (next === 't') out += '\t'
        else if (next === '"') out += '"'
        else if (next === '\\') out += '\\'
        else throw new Error(`line ${lineNo}: bad escape \\${next}`)
        j++
      } else {
        out += ch
      }
    }
    return out
  }
  const semi = rawValue.indexOf(';')
  if (semi !== -1) return rawValue.slice(0, semi).trim()
  return rawValue
}
